note_models.css:
.card {
  font-family: sans-serif;
  font-size: 35px;
  text-align: center;
  line-height: 1.5;
}

hr { 
  margin: 0;
  border: none;
  height: 1px;
  background: #ccc;
}

.jp, .kanji-theme {
  font-family: "Hiragino Mincho ProN", "Hiragino Mincho Pro", "ヒラギノ明朝 Pro", "Yu Mincho", "MS Mincho", "ＭＳ 明朝", "Noto Serif CJK JP", serif;
}

.jp { font-size: 100px; }
.kanji-theme {
  font-size: 15px;
  border: 1px solid;
  padding: 5px;
}

.meaning {
  margin: 25px 0;
  font-size: 28px;
}

.stroke-container {
  display: flex;
  justify-content: center;
  max-width: 100px;
  margin-left: auto;
  margin-right: auto;
}

.stroke-svg {
  width: 120px !important;
  height: 120px !important;
  max-width: 120px !important;
  max-height: 120px !important;
  margin: 25px 0;
  overflow: visible;
}

.nightMode .stroke-svg {
filter: invert(1) !important;
-webkit-filter: invert(1) !important;
}

.replay-btn {
  display: block;  /* 블록으로 중앙 */
  margin: 25px auto 0;  /* 상단 25px, 좌우 auto 중앙 */
  padding: 12px 28px;  /* 패딩 약간 늘림 */
  background: #667eea;
  color: white;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 16px;
  font-family: sans-serif;
  min-width: 140px;  /* 최소 너비 균일 */
}

.replay-btn:hover {
  background: #5a67d8;
}
